import { NavLink } from "react-router-dom";


function Navbar(){
    return(
        <nav>
            <NavLink to="/">Home</NavLink>
            <NavLink to="/about">About</NavLink>
            <NavLink to="/inventory">Inventory</NavLink>
            <NavLink to="/search">Search</NavLink>
        </nav>
    )
}

export default Navbar;
